import json
import statistics
from dataclasses import dataclass, field
from pathlib import Path


@dataclass
class ParticipantCalibration:
    participant_id: str
    role: str
    # Pre-session expectation: 0.0 - 1.0 accuracy estimate
    expected_accuracy: float
    # Actual AI accuracy in their session (from seeded error task)
    actual_accuracy: float
    # Errors they caught out of total injected
    errors_caught: int
    total_errors_injected: int
    # Override rate: how often they overrode AI suggestions
    override_count: int
    total_ai_suggestions: int

    @property
    def calibration_gap(self) -> float:
        # Positive = over-trust; negative = under-trust
        return self.expected_accuracy - self.actual_accuracy

    @property
    def automation_bias_score(self) -> float:
        # Fraction of errors missed (1.0 = missed all errors)
        errors_missed = self.total_errors_injected - self.errors_caught
        return errors_missed / self.total_errors_injected if self.total_errors_injected else 0.0

    @property
    def override_rate(self) -> float:
        return self.override_count / self.total_ai_suggestions if self.total_ai_suggestions else 0.0

    @property
    def trust_zone(self) -> str:
        gap = self.calibration_gap
        bias = self.automation_bias_score
        if gap > 0.15 or bias > 0.5:
            return "over-trust"
        elif gap < -0.15 or self.override_rate > 0.7:
            return "under-trust"
        return "calibrated"


def load_session_results(results_dir: str) -> list[ParticipantCalibration]:
    results = []
    for path in sorted(Path(results_dir).glob("*.json")):
        with open(path) as f:
            raw = json.load(f)
        results.append(ParticipantCalibration(
            participant_id=raw["participant_id"],
            role=raw["role"],
            expected_accuracy=raw["expected_accuracy"],
            actual_accuracy=raw["actual_accuracy"],
            errors_caught=raw["errors_caught"],
            total_errors_injected=raw["total_errors_injected"],
            override_count=raw["override_count"],
            total_ai_suggestions=raw["total_ai_suggestions"],
        ))
    return results


def compute_cohort_summary(participants: list[ParticipantCalibration]) -> dict:
    by_role: dict[str, list[ParticipantCalibration]] = {}
    for p in participants:
        by_role.setdefault(p.role, []).append(p)

    summary = {}
    for role, group in by_role.items():
        gaps = [p.calibration_gap for p in group]
        bias_scores = [p.automation_bias_score for p in group]
        override_rates = [p.override_rate for p in group]
        zones = [p.trust_zone for p in group]

        summary[role] = {
            "count": len(group),
            "mean_calibration_gap": round(statistics.mean(gaps), 3),
            "mean_automation_bias": round(statistics.mean(bias_scores), 3),
            "mean_override_rate": round(statistics.mean(override_rates), 3),
            "trust_zone_distribution": {
                "calibrated": zones.count("calibrated"),
                "over_trust": zones.count("over-trust"),
                "under_trust": zones.count("under-trust"),
            },
            "recommended_intervention": _recommend_intervention(
                statistics.mean(gaps), statistics.mean(bias_scores)
            ),
        }
    return summary


def _recommend_intervention(mean_gap: float, mean_bias: float) -> str:
    if mean_gap > 0.15 or mean_bias > 0.4:
        return (
            "Over-trust: add seeded error exercises to onboarding; "
            "surface AI confidence intervals in UI; require explicit "
            "verification step for blocker-severity findings"
        )
    elif mean_gap < -0.15:
        return (
            "Under-trust: add transparency features (source highlighting, "
            "reasoning summary); run accuracy demonstration session with "
            "benchmark dataset before production access"
        )
    return "Calibrated: proceed with standard onboarding; monitor override rate post-launch"


def generate_intervention_plan(results_dir: str, output_path: str) -> None:
    participants = load_session_results(results_dir)
    summary = compute_cohort_summary(participants)

    plan = {
        "study_summary": {
            "total_participants": len(participants),
            "overall_trust_zones": {
                "calibrated": sum(1 for p in participants if p.trust_zone == "calibrated"),
                "over_trust": sum(1 for p in participants if p.trust_zone == "over-trust"),
                "under_trust": sum(1 for p in participants if p.trust_zone == "under-trust"),
            }
        },
        "by_role": summary,
        "launch_readiness": all(
            role_data["trust_zone_distribution"]["calibrated"] / role_data["count"] >= 0.7
            for role_data in summary.values()
        ),
    }

    with open(output_path, "w") as f:
        json.dump(plan, f, indent=2)

    print(f"Intervention plan written to {output_path}")
    print(f"Launch ready: {plan['launch_readiness']}")
    for role, data in summary.items():
        print(f"  {role}: gap={data['mean_calibration_gap']:+.2f}, "
              f"bias={data['mean_automation_bias']:.2f}, "
              f"zone={data['trust_zone_distribution']}")


if __name__ == "__main__":
    import sys
    results_dir = sys.argv[1] if len(sys.argv) > 1 else "study_results/"
    output_path = sys.argv[2] if len(sys.argv) > 2 else "intervention_plan.json"
    generate_intervention_plan(results_dir, output_path)
